        // after replacing certain characters with '*'
        // This uses the fact that the number of substrings containing at least one '*'
        // is equal to total substrings - substrings with no '*' 
        // We use prefix sums to calculate the number of substrings with no '*' 
        // between the positions of '*' 
        // This is an optimized approach for large n
        // Time complexity: O(n)
        // Space complexity: O(n)
        void calculateValidSubstrings(boolean[] replaced) {
            int starCount = 0;
            long totalSubstrings = (long) n * (n + 1) / 2;
            long noStarSubstrings = 0;
            long prev = 0;

            for (int i = 0; i < n; i++) {
                if (replaced[i]) {
                    starCount++;
                    noStarSubstrings += (long) (i - prev) * (i - prev + 1) / 2;
                    prev = i + 1;
                }
            }
            noStarSubstrings += (long) (n - prev) * (n - prev + 1) / 2;
            count[0] = totalSubstrings - noStarSubstrings;
        }

        // Binary search for the minimum time t
        long left = 0, right = n - 1;
        long answer = -1;

        while (left <= right) {
            long mid = (left + right) / 2;
            boolean[] temp = Arrays.copyOf(replaced, replaced.length);
            for (int i = 0; i <= mid; i++) {
                temp[(int) order[i]] = true;
            }
            calculateValidSubstrings(temp);
            if (count[0] >= k) {
                answer = mid;
                right = mid - 1;
            } else {
                left = mid + 1;
            }
        }

        return answer;
    }
